UPDATE account_tbl
SET balance = CASE
    WHEN account_number = #{fromAccountNumber} THEN balance - #{amount}
    WHEN account_number = #{toAccountNumber} THEN balance + #{amount}
    ELSE balance
END
WHERE account_number IN (#{fromAccountNumber}, #{toAccountNumber});

